# Category: ssrf

import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.stream.scaladsl.Source

import scala.concurrent.ExecutionContextExecutor
import scala.io.Source.fromInputStream

object WebhookProxy {
  implicit val system: ActorSystem = ActorSystem()
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher

  def main(args: Array[String]): Unit = {
    val route =
      pathPrefix("webhook") {
        post {
          entity(as[String]) { userUrl =>
            complete {
              Http().singleRequest(HttpRequest(uri = userUrl)) mapResponse { response =>
                val statusCode = response.status.intValue()
                if (statusCode == HttpResponseCreated.INT_CODE) {
                  Source(fromInputStream(response.entity)).getLines.map(_.stripMargin).runWith(marshal(MediaTypes.`text/plain`))
                } else {
                  Complete((statusCode, "Error fetching content from provided URL"))
                }
              } recover {
                case e => Complete((HttpResponseBadRequest.INT_CODE, s"Error while fetching content: $e"))
              }
            }
          }
        }
      }

    val bindingFuture = Http().bindAndHandle(route, interface = "localhost", port = 8080)
    println(s"Server online at http://localhost:8080/")
    bindingFuture
      .flatMap(_.unbind()) // trigger unbinding from the port
      .onComplete(_ => system.terminate()) // and terminate when done...
  }
}